/**
 * @file fft_radix5_avx2_dit_tw_log3.h
 * @brief DFT-5 AVX2 DIT twiddled (log3 derived)
 *
 * Monolithic DFT-5 butterfly, 4 constants, peak 16 YMMs.
 * k-step=4
 * Generated by gen_radix5.py
 *
 * -- Operation counts per k-step --
 *
 *   kernel                 add   sub   mul   neg   fma   fms | arith flops |  ld  st  mem
 *   -------------------- ----- ----- ----- ----- ----- ----- + ----- ----- + --- --- ----
 *   bwd                     12    10    18     0    15     9 |    64    88 |  12  10   22
 *   fwd                     12    10    18     0    15     9 |    64    88 |  12  10   22
 *
 */

#ifndef FFT_RADIX5_AVX2_DIT_TW_LOG3_H
#define FFT_RADIX5_AVX2_DIT_TW_LOG3_H

#include <immintrin.h>

#ifndef R5A_LD
#define R5A_LD(p) _mm256_load_pd(p)
#define R5A_ST(p,v) _mm256_store_pd((p),(v))
#endif
#define LD R5A_LD
#define ST R5A_ST

static __attribute__((target("avx2,fma"))) void
radix5_tw_log3_dit_kernel_fwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d cA = _mm256_set1_pd(0.559016994374947451262869435595348477363586426);
    const __m256d cB = _mm256_set1_pd(0.951056516295153531181938433292089030146598816);
    const __m256d cC = _mm256_set1_pd(0.587785252292473137103456792829092592000961304);
    const __m256d cD = _mm256_set1_pd(0.250000000000000000000000000000000000000000000);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im,x4_re,x4_im;

    for (size_t k = 0; k < K; k += 4) {
        /* Load base twiddle w1, derive w2..w4 */
        const __m256d w1r = LD(&tw_re[0*K+k]), w1i = LD(&tw_im[0*K+k]);
        __m256d w2r, w2i;
        w2r = _mm256_fmsub_pd(w1r,w1r,_mm256_mul_pd(w1i,w1i));
        w2i = _mm256_fmadd_pd(w1r,w1i,_mm256_mul_pd(w1i,w1r));
        __m256d w3r, w3i;
        w3r = _mm256_fmsub_pd(w1r,w2r,_mm256_mul_pd(w1i,w2i));
        w3i = _mm256_fmadd_pd(w1r,w2i,_mm256_mul_pd(w1i,w2r));
        __m256d w4r, w4i;
        w4r = _mm256_fmsub_pd(w1r,w3r,_mm256_mul_pd(w1i,w3i));
        w4i = _mm256_fmadd_pd(w1r,w3i,_mm256_mul_pd(w1i,w3r));

        x0_re = LD(&in_re[0*K+k]);
        x0_im = LD(&in_im[0*K+k]);
        x1_re = LD(&in_re[1*K+k]);
        x1_im = LD(&in_im[1*K+k]);
        x2_re = LD(&in_re[2*K+k]);
        x2_im = LD(&in_im[2*K+k]);
        x3_re = LD(&in_re[3*K+k]);
        x3_im = LD(&in_im[3*K+k]);
        x4_re = LD(&in_re[4*K+k]);
        x4_im = LD(&in_im[4*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmsub_pd(x1_re,w1r,_mm256_mul_pd(x1_im,w1i));
          x1_im = _mm256_fmadd_pd(tr,w1i,_mm256_mul_pd(x1_im,w1r)); }
        { __m256d tr = x2_re;
          x2_re = _mm256_fmsub_pd(x2_re,w2r,_mm256_mul_pd(x2_im,w2i));
          x2_im = _mm256_fmadd_pd(tr,w2i,_mm256_mul_pd(x2_im,w2r)); }
        { __m256d tr = x3_re;
          x3_re = _mm256_fmsub_pd(x3_re,w3r,_mm256_mul_pd(x3_im,w3i));
          x3_im = _mm256_fmadd_pd(tr,w3i,_mm256_mul_pd(x3_im,w3r)); }
        { __m256d tr = x4_re;
          x4_re = _mm256_fmsub_pd(x4_re,w4r,_mm256_mul_pd(x4_im,w4i));
          x4_im = _mm256_fmadd_pd(tr,w4i,_mm256_mul_pd(x4_im,w4r)); }

        /* DFT-5 butterfly [fwd] */
        __m256d s1r=_mm256_add_pd(x1_re,x4_re), s1i=_mm256_add_pd(x1_im,x4_im);
        __m256d d1r=_mm256_sub_pd(x1_re,x4_re), d1i=_mm256_sub_pd(x1_im,x4_im);
        __m256d s2r=_mm256_add_pd(x2_re,x3_re), s2i=_mm256_add_pd(x2_im,x3_im);
        __m256d d2r=_mm256_sub_pd(x2_re,x3_re), d2i=_mm256_sub_pd(x2_im,x3_im);
        __m256d ss_r=_mm256_add_pd(s1r,s2r), ss_i=_mm256_add_pd(s1i,s2i);
        __m256d sd_r=_mm256_sub_pd(s1r,s2r), sd_i=_mm256_sub_pd(s1i,s2i);
        __m256d t0r=_mm256_fnmadd_pd(cD,ss_r,x0_re), t0i=_mm256_fnmadd_pd(cD,ss_i,x0_im);
        x0_re=_mm256_add_pd(x0_re,ss_r); x0_im=_mm256_add_pd(x0_im,ss_i);
        __m256d p1r=_mm256_fmadd_pd(cA,sd_r,t0r), p1i=_mm256_fmadd_pd(cA,sd_i,t0i);
        __m256d p2r=_mm256_fnmadd_pd(cA,sd_r,t0r), p2i=_mm256_fnmadd_pd(cA,sd_i,t0i);
        __m256d qar=_mm256_fmadd_pd(cC,d2i,_mm256_mul_pd(cB,d1i)), qai=_mm256_fmadd_pd(cC,d2r,_mm256_mul_pd(cB,d1r));
        __m256d qbr=_mm256_fmsub_pd(cB,d2i,_mm256_mul_pd(cC,d1i)), qbi=_mm256_fmsub_pd(cB,d2r,_mm256_mul_pd(cC,d1r));
        x1_re=_mm256_add_pd(p1r,qar); x1_im=_mm256_sub_pd(p1i,qai);
        x4_re=_mm256_sub_pd(p1r,qar); x4_im=_mm256_add_pd(p1i,qai);
        x2_re=_mm256_sub_pd(p2r,qbr); x2_im=_mm256_add_pd(p2i,qbi);
        x3_re=_mm256_add_pd(p2r,qbr); x3_im=_mm256_sub_pd(p2i,qbi);

        ST(&out_re[0*K+k], x0_re);
        ST(&out_im[0*K+k], x0_im);
        ST(&out_re[1*K+k], x1_re);
        ST(&out_im[1*K+k], x1_im);
        ST(&out_re[2*K+k], x2_re);
        ST(&out_im[2*K+k], x2_im);
        ST(&out_re[3*K+k], x3_re);
        ST(&out_im[3*K+k], x3_im);
        ST(&out_re[4*K+k], x4_re);
        ST(&out_im[4*K+k], x4_im);
    }
}

static __attribute__((target("avx2,fma"))) void
radix5_tw_log3_dit_kernel_bwd_avx2(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    const __m256d sign_flip = _mm256_set1_pd(-0.0);
    const __m256d cA = _mm256_set1_pd(0.559016994374947451262869435595348477363586426);
    const __m256d cB = _mm256_set1_pd(0.951056516295153531181938433292089030146598816);
    const __m256d cC = _mm256_set1_pd(0.587785252292473137103456792829092592000961304);
    const __m256d cD = _mm256_set1_pd(0.250000000000000000000000000000000000000000000);
    (void)sign_flip;  /* unused by current butterfly, reserved for neg() */

    __m256d x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im,x4_re,x4_im;

    for (size_t k = 0; k < K; k += 4) {
        /* Load base twiddle w1, derive w2..w4 */
        const __m256d w1r = LD(&tw_re[0*K+k]), w1i = LD(&tw_im[0*K+k]);
        __m256d w2r, w2i;
        w2r = _mm256_fmsub_pd(w1r,w1r,_mm256_mul_pd(w1i,w1i));
        w2i = _mm256_fmadd_pd(w1r,w1i,_mm256_mul_pd(w1i,w1r));
        __m256d w3r, w3i;
        w3r = _mm256_fmsub_pd(w1r,w2r,_mm256_mul_pd(w1i,w2i));
        w3i = _mm256_fmadd_pd(w1r,w2i,_mm256_mul_pd(w1i,w2r));
        __m256d w4r, w4i;
        w4r = _mm256_fmsub_pd(w1r,w3r,_mm256_mul_pd(w1i,w3i));
        w4i = _mm256_fmadd_pd(w1r,w3i,_mm256_mul_pd(w1i,w3r));

        x0_re = LD(&in_re[0*K+k]);
        x0_im = LD(&in_im[0*K+k]);
        x1_re = LD(&in_re[1*K+k]);
        x1_im = LD(&in_im[1*K+k]);
        x2_re = LD(&in_re[2*K+k]);
        x2_im = LD(&in_im[2*K+k]);
        x3_re = LD(&in_re[3*K+k]);
        x3_im = LD(&in_im[3*K+k]);
        x4_re = LD(&in_re[4*K+k]);
        x4_im = LD(&in_im[4*K+k]);
        { __m256d tr = x1_re;
          x1_re = _mm256_fmadd_pd(x1_re,w1r,_mm256_mul_pd(x1_im,w1i));
          x1_im = _mm256_fmsub_pd(x1_im,w1r,_mm256_mul_pd(tr,w1i)); }
        { __m256d tr = x2_re;
          x2_re = _mm256_fmadd_pd(x2_re,w2r,_mm256_mul_pd(x2_im,w2i));
          x2_im = _mm256_fmsub_pd(x2_im,w2r,_mm256_mul_pd(tr,w2i)); }
        { __m256d tr = x3_re;
          x3_re = _mm256_fmadd_pd(x3_re,w3r,_mm256_mul_pd(x3_im,w3i));
          x3_im = _mm256_fmsub_pd(x3_im,w3r,_mm256_mul_pd(tr,w3i)); }
        { __m256d tr = x4_re;
          x4_re = _mm256_fmadd_pd(x4_re,w4r,_mm256_mul_pd(x4_im,w4i));
          x4_im = _mm256_fmsub_pd(x4_im,w4r,_mm256_mul_pd(tr,w4i)); }

        /* DFT-5 butterfly [bwd] */
        __m256d s1r=_mm256_add_pd(x1_re,x4_re), s1i=_mm256_add_pd(x1_im,x4_im);
        __m256d d1r=_mm256_sub_pd(x1_re,x4_re), d1i=_mm256_sub_pd(x1_im,x4_im);
        __m256d s2r=_mm256_add_pd(x2_re,x3_re), s2i=_mm256_add_pd(x2_im,x3_im);
        __m256d d2r=_mm256_sub_pd(x2_re,x3_re), d2i=_mm256_sub_pd(x2_im,x3_im);
        __m256d ss_r=_mm256_add_pd(s1r,s2r), ss_i=_mm256_add_pd(s1i,s2i);
        __m256d sd_r=_mm256_sub_pd(s1r,s2r), sd_i=_mm256_sub_pd(s1i,s2i);
        __m256d t0r=_mm256_fnmadd_pd(cD,ss_r,x0_re), t0i=_mm256_fnmadd_pd(cD,ss_i,x0_im);
        x0_re=_mm256_add_pd(x0_re,ss_r); x0_im=_mm256_add_pd(x0_im,ss_i);
        __m256d p1r=_mm256_fmadd_pd(cA,sd_r,t0r), p1i=_mm256_fmadd_pd(cA,sd_i,t0i);
        __m256d p2r=_mm256_fnmadd_pd(cA,sd_r,t0r), p2i=_mm256_fnmadd_pd(cA,sd_i,t0i);
        __m256d qar=_mm256_fmadd_pd(cC,d2i,_mm256_mul_pd(cB,d1i)), qai=_mm256_fmadd_pd(cC,d2r,_mm256_mul_pd(cB,d1r));
        __m256d qbr=_mm256_fmsub_pd(cB,d2i,_mm256_mul_pd(cC,d1i)), qbi=_mm256_fmsub_pd(cB,d2r,_mm256_mul_pd(cC,d1r));
        x1_re=_mm256_sub_pd(p1r,qar); x1_im=_mm256_add_pd(p1i,qai);
        x4_re=_mm256_add_pd(p1r,qar); x4_im=_mm256_sub_pd(p1i,qai);
        x2_re=_mm256_add_pd(p2r,qbr); x2_im=_mm256_sub_pd(p2i,qbi);
        x3_re=_mm256_sub_pd(p2r,qbr); x3_im=_mm256_add_pd(p2i,qbi);

        ST(&out_re[0*K+k], x0_re);
        ST(&out_im[0*K+k], x0_im);
        ST(&out_re[1*K+k], x1_re);
        ST(&out_im[1*K+k], x1_im);
        ST(&out_re[2*K+k], x2_re);
        ST(&out_im[2*K+k], x2_im);
        ST(&out_re[3*K+k], x3_re);
        ST(&out_im[3*K+k], x3_im);
        ST(&out_re[4*K+k], x4_re);
        ST(&out_im[4*K+k], x4_im);
    }
}

#undef LD
#undef ST

#endif /* FFT_RADIX5_AVX2_DIT_TW_LOG3_H */
